import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { returnsService } from '../services/returns';
import {
  Card, StatusBadge, RiskBar, MLScorePanel, LoadingScreen, Alert, Button,
} from '../components/UI';
import { formatDate, formatReason, getErrorMessage } from '../utils/helpers';
import {
  ArrowLeft, Package, Calendar, FileText, AlertTriangle,
  Image as ImageIcon, Brain, Info, ExternalLink,
} from 'lucide-react';

export default function CustomerReturnStatus() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [lightbox, setLightbox] = useState(null);

  useEffect(() => {
    returnsService.getReturn(id)
      .then(r => setData(r.data))
      .catch(e => setError(getErrorMessage(e)))
      .finally(() => setLoading(false));
  }, [id]);

  if (loading) return <LoadingScreen />;
  if (error) return (
    <div className="max-w-2xl mx-auto px-4 py-8">
      <Alert type="error" message={error} />
    </div>
  );
  if (!data) return null;

  return (
    <div className="max-w-3xl mx-auto px-4 py-8 space-y-5 animate-fade-in">
      {/* Header */}
      <div className="flex items-center gap-3">
        <Button variant="ghost" size="sm" icon={ArrowLeft} onClick={() => navigate(-1)}>Back</Button>
        <div className="flex-1">
          <h1 className="font-display text-xl font-bold text-slate-900">
            Return Request #{data.id}
          </h1>
          <p className="text-xs text-slate-400">Submitted {formatDate(data.created_at)}</p>
        </div>
        <StatusBadge status={data.status} />
      </div>

      {/* Product Info */}
      <Card className="p-5">
        <div className="flex items-center gap-2 mb-4">
          <Package className="w-4 h-4 text-slate-400" />
          <h2 className="font-semibold text-slate-700 text-sm">Product Details</h2>
        </div>
        <div className="grid grid-cols-2 sm:grid-cols-3 gap-4">
          {[
            { label: 'Order ID', value: `#${data.order_id}`, mono: true },
            { label: 'Product Name', value: data.product_name },
            { label: 'Return Reason', value: formatReason(data.return_reason) },
            { label: 'Delivery Date', value: formatDate(data.delivery_date) },
            { label: 'Status', value: <StatusBadge status={data.status} /> },
            { label: 'Submitted', value: formatDate(data.created_at) },
          ].map(({ label, value, mono }) => (
            <div key={label}>
              <p className="text-xs text-slate-400 mb-0.5">{label}</p>
              {typeof value === 'string'
                ? <p className={`text-sm font-semibold text-slate-800 ${mono ? 'font-mono' : ''}`}>{value}</p>
                : value
              }
            </div>
          ))}
        </div>
        {data.description && (
          <div className="mt-4 pt-4 border-t border-slate-100">
            <div className="flex items-center gap-1.5 mb-1.5">
              <FileText className="w-3.5 h-3.5 text-slate-400" />
              <p className="text-xs font-semibold text-slate-500">Description</p>
            </div>
            <p className="text-sm text-slate-700 leading-relaxed">{data.description}</p>
          </div>
        )}
      </Card>

      {/* AI Analysis */}
      <Card className="p-5">
        <div className="flex items-center gap-2 mb-4">
          <Brain className="w-4 h-4 text-indigo-500" />
          <h2 className="font-semibold text-slate-700 text-sm">AI Risk Analysis</h2>
          <span className="ml-auto text-xs font-mono text-slate-400 bg-slate-100 px-2 py-0.5 rounded">
            v{data.ml_analysis?.model_versions?.fraud_classifier?.split('-')[1] || '2.1'}
          </span>
        </div>
        <MLScorePanel data={data} />

        {data.risk_factors?.length > 0 && (
          <div className="mt-4 pt-4 border-t border-slate-100">
            <div className="flex items-center gap-1.5 mb-2">
              <AlertTriangle className="w-3.5 h-3.5 text-amber-500" />
              <p className="text-xs font-bold text-slate-600">Risk Factors Identified</p>
            </div>
            <ul className="space-y-1">
              {data.risk_factors.map((f, i) => (
                <li key={i} className="flex items-start gap-2 text-xs text-slate-600">
                  <span className="text-amber-500 mt-0.5">•</span>
                  {f}
                </li>
              ))}
            </ul>
          </div>
        )}

        <div className="mt-4 pt-4 border-t border-slate-100">
          <div className="flex items-center gap-1.5 mb-2">
            <Info className="w-3.5 h-3.5 text-slate-400" />
            <p className="text-xs font-semibold text-slate-500">Models Used</p>
          </div>
          <div className="flex flex-wrap gap-2">
            {Object.entries(data.ml_analysis?.model_versions || {}).map(([k, v]) => (
              <span key={k} className="text-[10px] font-mono bg-slate-100 text-slate-600 px-2 py-0.5 rounded">
                {v}
              </span>
            ))}
          </div>
        </div>
      </Card>

      {/* Images */}
      {data.images?.length > 0 && (
        <Card className="p-5">
          <div className="flex items-center gap-2 mb-4">
            <ImageIcon className="w-4 h-4 text-slate-400" />
            <h2 className="font-semibold text-slate-700 text-sm">Submitted Images ({data.images.length})</h2>
          </div>
          <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
            {data.images.map((img, i) => (
              <div
                key={img.id}
                className="relative group rounded-xl overflow-hidden border border-slate-200 aspect-square bg-slate-50 cursor-pointer"
                onClick={() => setLightbox(img.image_url)}
              >
                <img src={img.image_url} alt={`Product ${i + 1}`} className="w-full h-full object-cover" />
                <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                  <ExternalLink className="w-5 h-5 text-white" />
                </div>
                {img.manipulation_score > 0.5 && (
                  <div className="absolute top-1 right-1 bg-amber-500 text-white text-[9px] font-bold px-1.5 py-0.5 rounded">
                    ⚠
                  </div>
                )}
              </div>
            ))}
          </div>
        </Card>
      )}

      {/* Lightbox */}
      {lightbox && (
        <div
          className="fixed inset-0 bg-black/80 z-50 flex items-center justify-center p-4"
          onClick={() => setLightbox(null)}
        >
          <img src={lightbox} alt="Full size" className="max-w-full max-h-full rounded-xl shadow-2xl" />
        </div>
      )}
    </div>
  );
}
